#include <bits/stdc++.h>
using namespace std;
int n;
struct xs {
	string mz;
	int yw,sx,yy;
	int zf;
} gsx[1005];
bool qgxd(xs x,xs y) {
	if(abs(x.zf-y.zf)<=10&&
	abs(x.yw-y.yw)<=5&&
	abs(x.sx-y.sx)<=5&&
	abs(x.yy-y.yy)<=5) {
		return 1;
	} else {
		return 0;
	}
}
int main() {
	cin>>n;
	for(int i=0; i<n; i++) {
		cin>>gsx[i].mz>>gsx[i].yw>>gsx[i].sx>>gsx[i].yy;
		gsx[i].zf=gsx[i].yw+gsx[i].sx+gsx[i].yy;
	}
	for(int i=0; i<n; i++) {
		for(int j=i+1; j<=n; j++) {
			if(qgxd(gsx[i],gsx[j])) {
				cout<<gsx[i].mz<<" "<<gsx[j].mz<<"\n";
			}
		}
	}
	return 0;
}
